#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[1001];
        scanf("%s", S);
        int N = strlen(S);
        int r = 0, g = 0, b = 0;
        for (int i = 0; i < N; i++) {
            if (S[i] == 'r') r++;
            else if (S[i] == 'g') g++;
            else b++;
        }
        int ans = 0;
        for (int i = 0; i < N - 1; i++) {
            if (S[i] != S[i + 1]) ans++;
        }
        printf("%d\n", ans);
    }
    return 0;
}

