import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int N = S.length();
            int r = 0, g = 0, b = 0;
            for (int i = 0; i < N; i++) {
                if (S.charAt(i) == 'r') r++;
                else if (S.charAt(i) == 'g') g++;
                else b++;
            }
            int ans = 0;
            for (int i = 0; i < N - 1; i++) {
                if (S.charAt(i) != S.charAt(i + 1)) ans++;
            }
            System.out.println(ans);
        }
    }
}

